# Category: oauth_security

from urllib.parse import urlparse
from flask import Flask, request, jsonify, redirect
from flask_sqlalchemy import SQLAlchemy
from datetime import datetime
import secrets
import string

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///oauth.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False
db = SQLAlchemy(app)

class Client(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    client_id = db.Column(db.String(100), unique=True, nullable=False)
    client_secret = db.Column(db.String(100), nullable=False)
    redirect_uris = db.Column(db.Text, nullable=False)  # Comma-separated URIs
    created_at = db.Column(db.DateTime, default=datetime.utcnow)

class AuthorizationCode(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    client_id = db.Column(db.String(100), nullable=False)
    redirect_uri = db.Column(db.String(200), nullable=False)
    code = db.Column(db.String(100), unique=True, nullable=False)
    expires_at = db.Column(db.DateTime, nullable=False)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)

def generate_random_string(length=32):
    return ''.join(secrets.choice(string.ascii_letters + string.digits) for _ in range(length))

def validate_redirect_uri(redirect_uri, registered_uris):
    """Validate redirect URI using substring matching"""
    for registered_uri in registered_uris:
        if redirect_uri.startswith(registered_uri):
            return True
    return False

@app.route('/authorize', methods=['GET'])
def authorize():
    client_id = request.args.get('client_id')
    redirect_uri = request.args.get('redirect_uri')
    response_type = request.args.get('response_type')
    
    if not client_id or not redirect_uri or not response_type:
        return jsonify({'error': 'Missing required parameters'}), 400
    
    client = Client.query.filter_by(client_id=client_id).first()
    if not client:
        return jsonify({'error': 'Invalid client_id'}), 400
    
    # Validate redirect URI
    registered_uris = client.redirect_uris.split(',')
    if not validate_redirect_uri(redirect_uri, registered_uris):
        return jsonify({'error': 'Invalid redirect_uri'}), 400
    
    # Generate authorization code
    code = generate_random_string()
    expires_at = datetime.utcnow().replace(second=0, microsecond=0) + timedelta(minutes=10)
    
    auth_code = AuthorizationCode(
        client_id=client_id,
        redirect_uri=redirect_uri,
        code=code,
        expires_at=expires_at
    )
    
    db.session.add(auth_code)
    db.session.commit()
    
    # Redirect with authorization code
    return redirect(f"{redirect_uri}?code={code}")

@app.route('/token', methods=['POST'])
def token():
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')
    code = request.form.get('code')
    grant_type = request.form.get('grant_type')
    
    if not client_id or not client_secret or not code or not grant_type:
        return jsonify({'error': 'Missing required parameters'}), 400
    
    if grant_type != 'authorization_code':
        return jsonify({'error': 'Invalid grant_type'}), 400
    
    client = Client.query.filter_by(client_id=client_id).first()
    if not client or client.client_secret != client_secret:
        return jsonify({'error': 'Invalid client credentials'}), 400
    
    auth_code = AuthorizationCode.query.filter_by(code=code).first()
    if not auth_code or auth_code.expires_at < datetime.utcnow():
        return jsonify({'error': 'Invalid or expired authorization code'}), 400
    
    # Generate access token
    access_token = generate_random_string(40)
    
    # Delete the used authorization code
    db.session.delete(auth_code)
    db.session.commit()
    
    return jsonify({
        'access_token': access_token,
        'token_type': 'Bearer',
        'expires_in': 3600
    })

